ps.pstext:
if !IsFeatureImplemented(FEAT_SME) then EndOfDecode(Decode_UNDEF); end;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let dim : integer{} = VL DIV 32;
let mask1 : bits(PL) = P{}(a);
let mask2 : bits(PL) = P{}(b);
let operand1 : bits(VL) = Z{}(n);
let operand2 : bits(VL) = Z{}(m);
let operand3 : bits(dim*dim*32) = ZAtile{}(da, 32);
var result : bits(dim*dim*32);

for row = 0 to dim-1 do
    for col = 0 to dim-1 do
        // determine row/col predicates
        let prow_0 : boolean = (ActivePredicateElement{PL}(mask1, 2*row + 0, 16));
        let prow_1 : boolean = (ActivePredicateElement{PL}(mask1, 2*row + 1, 16));
        let pcol_0 : boolean = (ActivePredicateElement{PL}(mask2, 2*col + 0, 16));
        let pcol_1 : boolean = (ActivePredicateElement{PL}(mask2, 2*col + 1, 16));

        var sum : bits(32) = operand3[(row*dim+col)*:32];
        if (prow_0 && pcol_0) || (prow_1 && pcol_1) then
            var erow_0 : bits(16) = (if prow_0 then operand1[(2*row + 0)*:16] else FPZero{16}('0'));
            var erow_1 : bits(16) = (if prow_1 then operand1[(2*row + 1)*:16] else FPZero{16}('0'));
            let ecol_0 : bits(16) = (if pcol_0 then operand2[(2*col + 0)*:16]
                                        else FPZero{16}('0'));
            let ecol_1 : bits(16) = (if pcol_1 then operand2[(2*col + 1)*:16]
                                        else FPZero{16}('0'));
            let honor_altfp : boolean = FALSE;   // Alternate handling ignored
            if prow_0 then erow_0 = BFNeg(erow_0, honor_altfp); end;
            if prow_1 then erow_1 = BFNeg(erow_1, honor_altfp); end;
            sum = BFDotAdd(sum, erow_0, erow_1, ecol_0, ecol_1, FPCR());

        end;
        result[(row*dim+col)*:32] = sum;
    end;
end;

ZAtile{dim*dim*32}(da, 32) = result;
